mapper.select:
SELECT trade_date
FROM stock_benchmark_return_series
WHERE index_code = #{indexCode}
ORDER BY trade_date DESC
LIMIT #{limit}

SELECT symbol, trade_date AS tradeDate, open_price AS openPrice, high_price AS highPrice, low_price AS lowPrice, close_price AS closePrice, volume, source, updated_at AS updatedAt FROM stock_candle_daily WHERE symbol IN
#{symbol}
AND trade_date BETWEEN #{fromDate} AND #{toDate} ORDER BY symbol, trade_date

SELECT
    index_code AS indexCode,
    signal_date AS signalDate,
    symbol,
    horizon_days AS horizonDays,
    model_version AS modelVersion,
    factor,
    exposure_score AS exposureScore,
    coefficient,
    contribution_pct AS contributionPct,
    sample_count AS sampleCount,
    source,
    calculated_at AS calculatedAt
FROM stock_expected_return_factor_contribution
WHERE symbol = #{symbol}
  AND model_version = #{modelVersion}
  AND horizon_days = #{horizonDays}
  AND signal_date = (
      SELECT MAX(signal_date)
      FROM stock_expected_return_factor_contribution
      WHERE symbol = #{symbol}
        AND model_version = #{modelVersion}
        AND horizon_days = #{horizonDays}
  )
  AND index_code = (
      SELECT selected.index_code
      FROM (
          SELECT index_code
          FROM stock_expected_return_factor_contribution
          WHERE symbol = #{symbol}
            AND model_version = #{modelVersion}
            AND horizon_days = #{horizonDays}
            AND signal_date = (
                SELECT MAX(signal_date)
                FROM stock_expected_return_factor_contribution
                WHERE symbol = #{symbol}
                  AND model_version = #{modelVersion}
                  AND horizon_days = #{horizonDays}
            )
          GROUP BY index_code
          ORDER BY CASE index_code
              WHEN 'SP500' THEN 1
              WHEN 'NASDAQ100' THEN 2
              WHEN 'DOW30' THEN 3
              ELSE 9
          END
          LIMIT 1
      ) selected
  )
ORDER BY ABS(COALESCE(contribution_pct, 0)) DESC, factor

mapper.insert:
INSERT INTO stock_risk_free_rate_snapshot (
    index_code, series_code, rate_date, annual_rate_pct, source
)
VALUES (
    #{indexCode}, #{seriesCode}, #{rateDate}, #{annualRatePct}, #{source}
)
ON DUPLICATE KEY UPDATE
    annual_rate_pct = VALUES(annual_rate_pct),
    source = VALUES(source),
    calculated_at = CURRENT_TIMESTAMP

