DELETE FROM stock_expected_return_factor_contribution
WHERE index_code = #{indexCode}
  AND signal_date = #{signalDate}
  AND model_version = #{modelVersion}

DELETE FROM stock_expected_return_calibration
WHERE index_code = #{indexCode}
  AND model_version = #{modelVersion}

